#include <iostream>
#include <forward_list>

using namespace std;

int main()
{
    forward_list<int> numbers;
    numbers.push_front(30);
    numbers.push_front(20);
    numbers.push_front(10);

    for (forward_list<int>::iterator it = numbers.begin(); it != numbers.end(); it++)
    {
        cout << *it << " ";
    }

    return 0;
}

